// O n8n passa os dados através de $input.all()
const items = $input.all();

for (let item of items) {
  let tel = item.json.telefone;

  // Inicializa os campos como nulo/falso para evitar erros
  item.json.whatsapp_jid = null;
  item.json.eh_celular = false;

  if (!tel) continue;

  // 1. Limpeza: mantém apenas números
  let cleaned = tel.toString().replace(/\D/g, '');

  // 2. Normalização: remove o 55 inicial se o número vier com DDI (ex: 55119...)
  // para que possamos validar o DDD e o 9º dígito corretamente
  if (cleaned.length === 13 && cleaned.startsWith('55')) {
    cleaned = cleaned.substring(2);
  }

  // 3. Validação de Celular Brasileiro:
  // - Precisa ter 11 dígitos (DDD + 9 + 8 dígitos)
  // - O 3º dígito deve ser 9
  const isMobile = cleaned.length === 11 && cleaned[2] === '9';

  if (isMobile) {
    // 4. Formatação solicitada: 55 + DDD + 9XXXXXXXX + @s.whatsapp.net
    item.json.whatsapp_jid = `55${cleaned}@s.whatsapp.net`;
    item.json.eh_celular = true;
  }

  // Opcional: manter o número limpo sem o sufixo para outras conferências
  item.json.telefone_limpo = cleaned;
}

return items;
